import { MakeLogicType, actions, kea, listeners, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'
import { router } from 'kea-router'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'
import { urls } from 'scenes/urls'

import type { EmailConfigStatus } from '../../scenes/settings/supportSettingsLogic'

export interface ComposeAttachment {
    id: string
    name: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface composeTicketLogicValues {
    attachmentUploading: boolean
    attachments: ComposeAttachment[]
    bcc: string[]
    cc: string[]
    composingLoading: boolean
    emailConfigId: string
    emailConfigs: EmailConfigStatus[]
    emailConfigsLoading: boolean
    emailSubject: string
    isOpen: boolean
    recipientDistinctId: string
    recipientEmail: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface composeTicketLogicActions {
    closeComposeModal: () => {
        value: true
    }
    loadEmailConfigs: () => any
    loadEmailConfigsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadEmailConfigsSuccess: (
        emailConfigs: EmailConfigStatus[],
        payload?: any
    ) => {
        emailConfigs: EmailConfigStatus[]
        payload?: any
    }
    openComposeModal: (prefill?: { distinctId?: string; email?: string }) => {
        prefill:
            | {
                  distinctId?: string | undefined
                  email?: string | undefined
              }
            | undefined
    }
    addAttachments: (attachments: ComposeAttachment[]) => {
        attachments: ComposeAttachment[]
    }
    removeAttachment: (id: string) => {
        id: string
    }
    resetForm: () => {
        value: true
    }
    setAttachmentUploading: (uploading: boolean) => {
        uploading: boolean
    }
    setBcc: (bcc: string[]) => {
        bcc: string[]
    }
    setCc: (cc: string[]) => {
        cc: string[]
    }
    uploadAttachment: (files: File[]) => {
        files: File[]
    }
    setEmailConfigId: (configId: string) => {
        configId: string
    }
    setEmailSubject: (subject: string) => {
        subject: string
    }
    setRecipientDistinctId: (distinctId: string) => {
        distinctId: string
    }
    setRecipientEmail: (email: string) => {
        email: string
    }
    submitCompose: (
        message: string,
        richContent: Record<string, unknown> | null
    ) => {
        message: string
        richContent: Record<string, unknown> | null
    }
    submitComposeFinished: () => {
        value: true
    }
}

export type composeTicketLogicType = MakeLogicType<composeTicketLogicValues, composeTicketLogicActions>

export const composeTicketLogic = kea<composeTicketLogicType>([
    path(['products', 'conversations', 'frontend', 'components', 'ComposeTicket', 'composeTicketLogic']),
    actions({
        openComposeModal: (prefill?: { distinctId?: string; email?: string }) => ({ prefill }),
        closeComposeModal: true,
        setRecipientEmail: (email: string) => ({ email }),
        setRecipientDistinctId: (distinctId: string) => ({ distinctId }),
        setEmailSubject: (subject: string) => ({ subject }),
        setEmailConfigId: (configId: string) => ({ configId }),
        setCc: (cc: string[]) => ({ cc }),
        setBcc: (bcc: string[]) => ({ bcc }),
        uploadAttachment: (files: File[]) => ({ files }),
        addAttachments: (attachments: ComposeAttachment[]) => ({ attachments }),
        removeAttachment: (id: string) => ({ id }),
        setAttachmentUploading: (uploading: boolean) => ({ uploading }),
        resetForm: true,
        submitCompose: (message: string, richContent: Record<string, unknown> | null) => ({ message, richContent }),
        submitComposeFinished: true,
    }),
    reducers({
        isOpen: [
            false,
            {
                openComposeModal: () => true,
                closeComposeModal: () => false,
                resetForm: () => false,
            },
        ],
        recipientEmail: [
            '',
            {
                setRecipientEmail: (_, { email }) => email,
                openComposeModal: () => '',
                resetForm: () => '',
            },
        ],
        recipientDistinctId: [
            '',
            {
                setRecipientDistinctId: (_, { distinctId }) => distinctId,
                openComposeModal: () => '',
                resetForm: () => '',
            },
        ],
        emailSubject: [
            '',
            {
                setEmailSubject: (_, { subject }) => subject,
                openComposeModal: () => '',
                resetForm: () => '',
            },
        ],
        emailConfigId: [
            '',
            {
                setEmailConfigId: (_, { configId }) => configId,
                openComposeModal: () => '',
                resetForm: () => '',
            },
        ],
        cc: [
            [] as string[],
            {
                setCc: (_, { cc }) => cc,
                openComposeModal: () => [],
                resetForm: () => [],
            },
        ],
        bcc: [
            [] as string[],
            {
                setBcc: (_, { bcc }) => bcc,
                openComposeModal: () => [],
                resetForm: () => [],
            },
        ],
        attachments: [
            [] as ComposeAttachment[],
            {
                addAttachments: (state, { attachments }) => [...state, ...attachments],
                removeAttachment: (state, { id }) => state.filter((a) => a.id !== id),
                openComposeModal: () => [],
                resetForm: () => [],
            },
        ],
        attachmentUploading: [
            false,
            {
                setAttachmentUploading: (_, { uploading }) => uploading,
                openComposeModal: () => false,
                resetForm: () => false,
            },
        ],
        composingLoading: [
            false,
            {
                submitCompose: () => true,
                submitComposeFinished: () => false,
                openComposeModal: () => false,
                resetForm: () => false,
            },
        ],
    }),
    loaders({
        emailConfigs: [
            [] as EmailConfigStatus[],
            {
                loadEmailConfigs: async (): Promise<EmailConfigStatus[]> => {
                    try {
                        // nosemgrep: prefer-codegen-api
                        const response = await api.get('api/conversations/v1/email/status')
                        return response.configs || []
                    } catch {
                        return []
                    }
                },
            },
        ],
    }),
    listeners(({ actions, values }) => ({
        openComposeModal: ({ prefill }) => {
            if (prefill?.distinctId) {
                actions.setRecipientDistinctId(prefill.distinctId)
            }
            if (prefill?.email) {
                actions.setRecipientEmail(prefill.email)
            }
            actions.loadEmailConfigs()
        },
        uploadAttachment: async ({ files }) => {
            if (files.length === 0) {
                return
            }
            actions.setAttachmentUploading(true)
            try {
                const uploaded = await Promise.all(files.map((file) => api.conversationsTickets.uploadAttachment(file)))
                actions.addAttachments(uploaded.map((u) => ({ id: u.id, name: u.name })))
            } catch {
                lemonToast.error('Failed to upload attachment')
            } finally {
                actions.setAttachmentUploading(false)
            }
        },
        submitCompose: async ({ message, richContent }) => {
            const { recipientEmail, recipientDistinctId, emailSubject, emailConfigId, cc, bcc, attachments } = values

            if (!message.trim()) {
                lemonToast.error('Message is required.')
                actions.submitComposeFinished()
                return
            }

            if (!recipientEmail) {
                lemonToast.error('Recipient email is required.')
                actions.submitComposeFinished()
                return
            }

            if (!emailConfigId) {
                lemonToast.error('Please select a "From" email address.')
                actions.submitComposeFinished()
                return
            }

            try {
                const result = await api.conversationsTickets.compose({
                    message,
                    recipient_email: recipientEmail,
                    email_config_id: emailConfigId,
                    ...(recipientDistinctId ? { recipient_distinct_id: recipientDistinctId } : {}),
                    ...(emailSubject ? { email_subject: emailSubject } : {}),
                    ...(richContent ? { rich_content: richContent } : {}),
                    ...(cc.length > 0 ? { cc } : {}),
                    ...(bcc.length > 0 ? { bcc } : {}),
                    ...(attachments.length > 0 ? { attachment_media_ids: attachments.map((a) => a.id) } : {}),
                })

                lemonToast.success('Ticket created successfully.')
                actions.resetForm()
                router.actions.push(urls.supportTicketDetail(result.ticket_number))
            } catch (error: unknown) {
                const detail =
                    error && typeof error === 'object' && 'detail' in error
                        ? (error as { detail: string }).detail
                        : 'Failed to create ticket.'
                lemonToast.error(detail)
                actions.submitComposeFinished()
            }
        },
    })),
])
